package genxsolution.vms.vmsbackend.maintenance_management.maintenance_plan_item.service;
import genxsolution.vms.vmsbackend.maintenance_management.exception.MaintenanceResourceNotFoundException; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_plan_item.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_plan_item.mapper.MaintenancePlanItemMapper; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_plan_item.repository.MaintenancePlanItemRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class MaintenancePlanItemService { private final MaintenancePlanItemRepository repository; private final MaintenancePlanItemMapper mapper; public MaintenancePlanItemService(MaintenancePlanItemRepository repository,MaintenancePlanItemMapper mapper){this.repository=repository;this.mapper=mapper;} public List<MaintenancePlanItemResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public MaintenancePlanItemResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("MaintenancePlanItem", String.valueOf(id))); } public MaintenancePlanItemResponse create(MaintenancePlanItemUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public MaintenancePlanItemResponse update(UUID id,MaintenancePlanItemUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("MaintenancePlanItem", String.valueOf(id))); } public void delete(UUID id){ if(!repository.delete(id)) throw new MaintenanceResourceNotFoundException("MaintenancePlanItem", String.valueOf(id)); } }
